import azure.functions as func
import json
import hmac
import hashlib
import base64
import os
import logging
from datetime import datetime

app = func.FunctionApp()

# Use a securely stored secret for message signing
MESSAGE_SIGNING_KEY = os.environ.get("MESSAGE_SIGNING_KEY", "").encode("utf-8")


def sign_message(payload_bytes: bytes) -> str:
    """Create HMAC signature for message integrity verification."""
    return hmac.new(MESSAGE_SIGNING_KEY, payload_bytes, hashlib.sha256).hexdigest()


def verify_and_deserialize(message_body: str) -> dict:
    """
    Verify message integrity and deserialize using JSON.
    
    Messages are expected in format:
    {"signature": "<hmac_hex>", "payload": "<base64_encoded_json>"}
    """
    envelope = json.loads(message_body)

    if "signature" not in envelope or "payload" not in envelope:
        raise ValueError("Message missing required fields: 'signature' and 'payload'")

    payload_b64 = envelope["payload"]
    provided_signature = envelope["signature"]

    payload_bytes = base64.b64decode(payload_b64)

    expected_signature = sign_message(payload_bytes)
    if not hmac.compare_digest(provided_signature, expected_signature):
        raise ValueError("Message signature verification failed — possible tampering detected")

    data = json.loads(payload_bytes.decode("utf-8"))
    return data


def create_signed_message(data: dict) -> str:
    """
    Helper: Create a signed message envelope for producers to use.
    
    Usage by message producers:
        message = create_signed_message({"job_type": "resize_image", "params": {...}})
        # Send `message` to Service Bus queue
    """
    payload_bytes = json.dumps(data, default=str).encode("utf-8")
    signature = sign_message(payload_bytes)
    envelope = {
        "signature": signature,
        "payload": base64.b64encode(payload_bytes).decode("utf-8"),
    }
    return json.dumps(envelope)


# --- Job Handlers ---

def handle_resize_image(params: dict) -> dict:
    logging.info(f"Processing image resize: {params.get('image_id')}")
    return {"status": "completed", "image_id": params.get("image_id")}


def handle_send_email(params: dict) -> dict:
    logging.info(f"Processing email send to: {params.get('recipient')}")
    return {"status": "sent", "recipient": params.get("recipient")}


def handle_data_export(params: dict) -> dict:
    logging.info(f"Processing data export: {params.get('export_id')}")
    return {"status": "exported", "export_id": params.get("export_id")}


# Whitelist of allowed job types — prevents arbitrary function invocation
JOB_HANDLERS = {
    "resize_image": handle_resize_image,
    "send_email": handle_send_email,
    "data_export": handle_data_export,
}


@app.service_bus_queue_trigger(
    arg_name="msg",
    queue_name="job-processing-queue",
    connection="SERVICE_BUS_CONNECTION_STRING",
)
def process_job_queue(msg: func.ServiceBusMessage) -> None:
    """
    Process async job messages from Azure Service Bus.
    
    Uses JSON + HMAC signing instead of pickle for security.
    
    DO NOT use pickle.loads() on queue messages — it enables remote code execution.
    Example attack payload with pickle:
        import os; os.system('rm -rf / --no-preserve-root')
    This can be trivially embedded in a pickled object via __reduce__.
    """
    message_id = msg.message_id
    logging.info(f"Processing message: {message_id}")

    try:
        message_body = msg.get_body().decode("utf-8")

        # Securely deserialize with signature verification
        job_data = verify_and_deserialize(message_body)

        # Validate job structure
        job_type = job_data.get("job_type")
        params = job_data.get("params", {})
        job_id = job_data.get("job_id", "unknown")

        if not job_type:
            raise ValueError("Message missing 'job_type' field")

        # Only execute whitelisted job types
        handler = JOB_HANDLERS.get(job_type)
        if handler is None:
            raise ValueError(
                f"Unknown job type: '{job_type}'. "
                f"Allowed types: {list(JOB_HANDLERS.keys())}"
            )

        logging.info(f"Executing job {job_id} of type '{job_type}'")
        result = handler(params)
        logging.info(f"Job {job_id} completed: {result}")

    except ValueError as e:
        logging.error(f"Invalid message {message_id}: {e}")
        raise  # Let Service Bus handle dead-lettering

    except Exception as e:
        logging.exception(f"Failed to process message {message_id}: {e}")
        raise  # Retry via Service Bus retry policy


